#!/bin/bash\n# WebCraft AI - Quick Test Script\n# Run this script to verify all improvements\n\nset -e\n\necho \"=====================================\"\necho \"WebCraft AI - Verification Script\"\necho \"=====================================\"\necho \"\"\n\n# Colors for output\nGREEN='\\033[0;32m'\nBLUE='\\033[0;34m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\n# Check Docker\necho \"${BLUE}1. Checking Docker installation...${NC}\"\nif ! command -v docker &> /dev/null; then\n    echo \"❌ Docker not found. Please install Docker.\"\n    exit 1\nfi\ndocker --version\necho \"${GREEN}✓ Docker OK${NC}\"\necho \"\"\n\n# Check Docker Compose\necho \"${BLUE}2. Checking Docker Compose...${NC}\"\nif ! command -v docker-compose &> /dev/null; then\n    echo \"❌ Docker Compose not found. Please install Docker Compose.\"\n    exit 1\nfi\ndocker-compose --version\necho \"${GREEN}✓ Docker Compose OK${NC}\"\necho \"\"\n\n# Check Node (for local development)\necho \"${BLUE}3. Checking Node.js...${NC}\"\nif command -v node &> /dev/null; then\n    node --version\n    echo \"${GREEN}✓ Node.js installed${NC}\"\nelse\n    echo \"${YELLOW}⚠ Node.js not found (optional, required for local development)${NC}\"\nfi\necho \"\"\n\n# Build Docker image\necho \"${BLUE}4. Building Docker image...${NC}\"\necho \"This may take 2-3 minutes on first run...\"\ndocker-compose build --no-cache || {\n    echo \"${RED}❌ Docker build failed${NC}\"\n    exit 1\n}\necho \"${GREEN}✓ Docker build completed${NC}\"\necho \"\"\n\n# Start services\necho \"${BLUE}5. Starting services...${NC}\"\ndocker-compose down -v 2>/dev/null || true\ndocker-compose up -d\necho \"Waiting for services to start (30 seconds)...\"\nsleep 30\necho \"${GREEN}✓ Services started${NC}\"\necho \"\"\n\n# Check container status\necho \"${BLUE}6. Checking container status...${NC}\"\ndocker-compose ps\necho \"${GREEN}✓ Container status checked${NC}\"\necho \"\"\n\n# Test health endpoint\necho \"${BLUE}7. Testing health endpoint...${NC}\"\nif curl -s http://localhost:3000/health | grep -q \"ok\"; then\n    echo \"${GREEN}✓ Health check passed${NC}\"\nelse\n    echo \"${YELLOW}⚠ Health check not yet responding (may still be initializing)${NC}\"\nfi\necho \"\"\n\n# Test API endpoint\necho \"${BLUE}8. Testing API endpoint...${NC}\"\nif curl -s http://localhost:3000/api/agents > /dev/null 2>&1; then\n    echo \"${GREEN}✓ API endpoint responding${NC}\"\nelse\n    echo \"${YELLOW}⚠ API endpoint not yet responding (may still be initializing)${NC}\"\nfi\necho \"\"\n\n# Check logs\necho \"${BLUE}9. Checking application logs...${NC}\"\necho \"Recent app logs:\"\ndocker-compose logs app --tail=10\necho \"\"\n\n# Frontend test\necho \"${BLUE}10. Frontend accessibility test${NC}\"\necho \"Frontend is available at: ${BLUE}http://localhost:3000${NC}\"\necho \"Test the following:\"\necho \"  - Page loads without errors\"\necho \"  - Navigation responsive on mobile (use DevTools Ctrl+Shift+M)\"\necho \"  - All sections visible\"\necho \"  - No console errors (F12)\"\necho \"\"\n\n# Summary\necho \"${GREEN}=====================================${NC}\"\necho \"${GREEN}Verification Complete!${NC}\"\necho \"${GREEN}=====================================${NC}\"\necho \"\"\necho \"Next steps:\"\necho \"1. Open browser: ${BLUE}http://localhost:3000${NC}\"\necho \"2. Test responsive design: Press ${BLUE}Ctrl+Shift+M${NC} in Chrome\"\necho \"3. View logs: ${BLUE}docker-compose logs -f app${NC}\"\necho \"4. Stop services: ${BLUE}docker-compose down${NC}\"\necho \"\"\necho \"Documentation:\"\necho \"  - Setup guide: DOCKER_SETUP_GUIDE.md\"\necho \"  - Responsiveness: RESPONSIVENESS_FIXES.md\"\necho \"  - Testing guide: TESTING_GUIDE.md\"\necho \"  - Quick reference: QUICK_REFERENCE.md\"\necho \"\"\n